var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"그게 무슨 소리요?","JPN":"それはどういうことだ？","ENG":"What are you talking about?","TWN":"那是什麼意思？"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"내가 고용한 용병들이 교란 좌표에 속아 어딘지도 모를 곳으로 사라져 버렸다고?","JPN":"私が雇った傭兵たちが撹乱座標に騙されて、行方不明になっただと？","ENG":"The mercenaries I hired followed some decoy coordinates and disappeared into nowhere?","TWN":"我僱用的傭兵都被假的座標欺騙，消失在不知道是哪裡的地方？"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"댁들이랑 함선 몇 척만 남긴 채로?","JPN":"お前たちの会社の艦船と他の数隻だけを残したまま？","ENG":"Leaving you and a few other ships?","TWN":"只剩下你們跟幾艘艦船？"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"젠장…… 차라리 그 괴물을 불렀어야 했나……","JPN":"クソ……やっぱりあの化け物を呼ぶべきだったのか……","ENG":"Drat... Maybe I should have just called that monster...","TWN":"該死……早知道應該要找那個怪物來嗎……"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"이봐.","JPN":"おい。","ENG":"Hey.","TWN":"喂！"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"이렇게 된 이상 확실하게 말해 둬야겠군.","JPN":"こうなってしまった以上、確実にしておかねばならない。","ENG":"Now that this happened, I have no choice but to tell you.","TWN":"事已至此，我就把話說清楚！"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"그 연구선 안에는, 연합함대 절반을 버리면서까지 손에 넣은 물건이 들어 있어.","JPN":"あの研究船の中には、連合艦隊の半分を捨ててまで手に入れた物があるのだ。","ENG":"That research ship carries something that cost me half the Coalition Fleet.","TWN":"那艘研究船裡裝的是，幾乎犧牲掉全部聯合艦隊才弄到手的東西。"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"그걸 손에 넣기 위해 내가 얼마나 많은 시간과 비용을 투자했을지 짐작이 가나?","JPN":"それを手に入れるために、私がどれほど多くの時間と費用を投資したのかわかるか？","ENG":"Can you imagine how much time and money I spent to get it?","TWN":"你們知道我花了多少時間跟金錢，才把那個東西弄到手嗎？"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"그건 혁신이야! 퓨처 앳 워의 기술도 단숨에 구닥다리로 만들 혁신의 정수!","JPN":"それは革新だ！　フューチャーアットウォーの技術も時代遅れにできる革新そのもの！","ENG":"Innovation! That essence of innovation will put to shame any technology that Future-at-War has!","TWN":"那可是革新技術啊！是連天啟兵器的技術，也可以瞬間做出來的革新技術！"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"그러니 무슨 일이 있어도 되찾아야 돼! 반드시!","JPN":"だから何としても取り戻さなければならん！　必ず！","ENG":"I must get it back, no matter what!","TWN":"所以我不管你們用什麼方法，都要把那艘船找回來！"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_BIG"},{"id":"L13_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"그깟 용병 놈들,","JPN":"あんな傭兵どもなんて、","ENG":"I don't care","TWN":"區區的傭兵…"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":" 전멸하는 한이 있더라도 어떻게든……","JPN":"　全滅しても構わない……何とかせねば……","ENG":" if those mercenaries are wiped out. I must—","TWN":"就算要犧牲你們所有人，我也在所不惜……"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"안녕, 멍청이 용병들.","JPN":"やあ、バカな傭兵ども。","ENG":"Hello, stupid mercenaries.","TWN":"哈囉～愚蠢的傭兵們！"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L18_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"다들 알아서 함정에 처박혀 줘서 고마워.","JPN":"みんな簡単に罠に引っかかってくれてありがとう。","ENG":"Thank you for walking into our trap so voluntarily.","TWN":"首先，謝謝你們都自己落入陷阱裡。"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"어떻게든 우릴 먼저 잡아보려고 불나방처럼 달려드는 꼴이라니.","JPN":"何とか俺らを先に捕まえようとかかってくる様は、まさに飛んで火にいる夏の虫だな。","ENG":"You came after us like moths to a flame.","TWN":"為了要抓到我們，瞧你們那副飛蛾撲火的模樣。"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"마지막 순간까지 자기들이 쫓던 게 허수공간으로 통하는 가짜 좌표인 줄도 모르고 말이야.","JPN":"最後まで自分たちが追っていたのが虚数空間に通じる偽座標ってことに気付けないなんて。","ENG":"You had no idea you were following some fake coordinates connected to an imaginary space, did you?","TWN":"你們到最後一刻都沒發現，那是通往量子空間的假座標吧！"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"자, 쇼는 이제 끝났어.","JPN":"さあ、ショーは終わりだ。","ENG":"Alright, the show is over.","TWN":"好了好了，遊戲結束了。"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"살아남은 떨거지들은 얌전히 집으로 돌아가도록 해.","JPN":"生き残った虫どもは大人しく家に帰れ。","ENG":"Those of you who have survived should go back home like the good chaps you are.","TWN":"還沒死的，我勸你們乖乖回家吧！"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"이건 최종 통보야.","JPN":"これは最終通告だ。","ENG":"This is our final notice.","TWN":"這是最後通牒！"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"교신 종료.","JPN":"交信終了。","ENG":"Over and out.","TWN":"結束通訊。"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"좋아, 다이브 준비 상황은 어떻지?","JPN":"よし、ダイブの準備はどうだ？","ENG":"Alright, how are we doing with the Dive preparation?","TWN":"很好！躍入準備得如何？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"이터니움 드라이브 충전 70% 완료!","JPN":"エタニウムドライブチャージ70％完了！","ENG":"Our Eternium Drive is seventy percent charged.","TWN":"永恆之金引擎充電完成70%！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"담배 한 대 태우면서 기다리시면 서브스톰까지 직통으로 갈 수 있습니다요, 선장님!","JPN":"一服しながらお待ちいただければ、サブストームまで直通で行けますぜ、船長！","ENG":"Why don't you go have a smoke? We'll be in Substorm in no time, Captain.","TWN":"報告船長！您先抽根菸稍等一下，我們很快就可以直接通往次級風暴囉！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"확실히 검은 평의회에서 한 자리 차지할 만하군. ","JPN":"確かに黒の評議会で認められるだけの実力はあるな。","ENG":"There's a reason you're a member of the Dark Council. ","TWN":"事成之後應該可以在暗黑評議會取得一席之地吧！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"알파트릭스가 긁어 모은 용병들을 한 번에 정리하겠다고 했을 때는 잠꼬대인 줄 알았는데.","JPN":"アルファトリックスがかき集めた傭兵を一気に片付けると言った時は半信半疑だったが。","ENG":"I thought you were crazy, thinking you could take on Alphatrix's mercenary army.","TWN":"妳那時說要把阿爾法崔克斯找來的那些傭兵一次都處理掉，我原本以為是在吹牛呢！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"아부는 됐으니까 약속이나 어기지 마.","JPN":"お世辞はいいから約束だけはちゃんと守れ。","ENG":"Quit with the flattering, and don't forget your promise.","TWN":"拍馬屁的話就省省吧！記得我們的約定！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>녀석</color>을 완성하고 나면 그걸 조종하는 건 나야.","JPN":"<color=#ffd34c>やつ</color>が完成したら、それを操るのは俺だ。","ENG":"When we put <color=#ffd34c>it</color> back together, I'll be the one who controls it.","TWN":"等那<color=#ffd34c>傢伙</color>完成後，必須由我來操控！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"물론이다. 네가 그걸 통제할 수만 있다면 말이지.","JPN":"もちろん。お前がそれをコントロールできるなら、な。","ENG":"Of course. If you can control it, that is.","TWN":"那是當然的，前提是妳有辦法的話。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"몸체의 기동 준비는 방금 막 끝났다.","JPN":"胴体の起動準備はちょうど今終わった。","ENG":"The body's ready to be turned on.","TWN":"主體的啟動準備剛剛已經完成，"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"이제 저 연구선에서 머리만 꺼내면 돼.","JPN":"後はあの研究船から頭部を取り出すだけだ。","ENG":"Now, we just need to get its head out of that research ship.","TWN":"現在就差從研究船上把頭取下來。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"인내심을 조금만 더 발휘해 봐, 덩치.","JPN":"忍耐力をもう少しだけ発揮しろよ。","ENG":"Have some more patience, bravo.","TWN":"有點耐心好嗎，大塊頭？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"보안 시스템을 모두 장악하기까지 이제 얼마 안 남았으니까.","JPN":"セキュリティシステムをすべて掌握するまであと少しだ。","ENG":"I'm almost done disarming the security system.","TWN":"我還要一點時間才能完全掌握安全系統。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"하지만 들으면 들을수록 웃기는군.","JPN":"それにしても面白い話だな。","ENG":"But the more I hear about it, the more ridiculous it sounds.","TWN":"不過我真是越聽越覺得好笑。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"머리라고 해 봤자 결국 그냥 인공지능 모듈 아닌가?","JPN":"頭部と言っても結局、ただの人工知能モジュールだろ？","ENG":"It's just a head, equipped with an AI module.","TWN":"一直說它是頭，但說到底不就是個人工智慧模組嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"알파트릭스야 그렇다 치고, 몸체를 가진 너희들까지 왜 이걸 갖고 싶어 안달이지?","JPN":"アルファトリックスはとにかく、本体を持つお前らまでなぜこれが欲しいんだ？","ENG":"I get why Alphatrix wants it back. But you guys already have the body. Why do you need it so badly?","TWN":"阿爾法崔克斯就算了，但你們不是有主體嗎？怎麼連你們也這麼想得到這個東西？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"몸체는 얼마든지 다시 만들 수 있다.","JPN":"胴体ならいくらでも作り直せる。","ENG":"The body can be replaced.","TWN":"製作主體不是問題，要幾個有幾個。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"하지만 머리는 하나뿐이야.","JPN":"しかし頭部は一つだけだ。","ENG":"The head can't.","TWN":"但頭只有一個。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"머리가 하나뿐이라고?","JPN":"頭部が一つだけだと？","ENG":"What do you mean, the head can't?","TWN":"頭只有一個？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"인공지능 따위 얼마든지 다시 만들 수 있을 텐데, 그건 또 무슨 말장난인지 모르겠군.","JPN":"人工知能なんかいくらでも作り直せるはずなのに、それは何の言葉遊びなのかわからないな。","ENG":"You can recompile an AI anytime. I don't know what you're talking about.","TWN":"人工智慧這種東西也是要多少都做得出來，我聽不懂你在胡說什麼。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"뭐, 상관없나?","JPN":"まあ、いっか。","ENG":"Well, no matter.","TWN":"算了，無所謂。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"궁금한 건 직접 뜯어서 보는 편이 더 재밌으니까.","JPN":"気になるものは直接分解して確かめた方が面白そうだし。","ENG":"I can always dismantle it to satisfy my curiosity.","TWN":"謎底就是要自己揭曉才有趣。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"뭐지?!","JPN":"なんだ！？","ENG":"What happened?","TWN":"怎麼回事？！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"콜록, 콜록! 확인 중이니 잠깐 기다려 보십쇼!","JPN":"ゴホッ！　確認するからちょいお待ち！","ENG":"*Cough, cough!* I'm checking. Hold on!","TWN":"咳咳！咳咳！確認中，請稍候！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"어라, 뭔가가 우릴 쫓아온 모양인데?","JPN":"あれ、何かに追跡されてたみたいだな？","ENG":"Err, something followed us.","TWN":"啊咧？好像有東西追著我們到這裡來了？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"우왓! 방금 열린 차원항로로 살아남은 함선들이 들어오고 있잖아!","JPN":"おっと！　さっき開かれた次元航路に生き残った艦船が入ってきているじゃないか！","ENG":"Geez! The surviving ships are coming in through the dimensional route that just opened up!","TWN":"哇！那些存活的艦船，透過剛才打開的次元航道往我們這邊來了啦！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"두목! 이쪽으로 통하는 진입좌표는 전부 막아 뒀다고 하지 않았어?","JPN":"ボス！　こっちに通じる進入座標は全部塞いでおいたって聞いたんだが？","ENG":"Boss! Didn't you say you blocked all the coordinates that led this way?","TWN":"老大！妳不是說通往我們這裡的座標都堵住了嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"그럴 리가!","JPN":"そんなはずが！","ENG":"No way!","TWN":"這怎麼可能！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"그 짧은 시간 안에 내가 살포한 교란 좌표를 모두 간파했다고? 대체 어떻게?","JPN":"あの短時間で俺が散布した撹乱座標をすべて見抜いただと？　一体どうやって？","ENG":"They can't have filtered out all my decoy coordinates in that short amount of time... Can they?","TWN":"在這麼短的時間內，就識破所有我設下的假座標？這怎麼可能？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"연구선을 인양 중인 적 함선, 발견했습니다.","JPN":"研究船を引き揚げ中の敵艦船、発見しました。","ENG":"We've detected the enemy vessel hauling the research ship.","TWN":"發現劫走研究船的目標艦船。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"훗, 다들 컴퓨터 항법 장치에 너무 의존하니까 그런 함정에 당하는 겁니다.","JPN":"ふっ、みんなコンピューターの航法装置に依存しすぎるから、そんな落とし穴にはまるのです。","ENG":"Hah. The others got fooled because they only relied on their computer navigation system.","TWN":"哈，大家就是太依賴電腦的定位系統，才會被那種艦船騙啦！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"이면세계의 미로 속에서 따라야 할 것은 오직 요정님의 인도뿐!","JPN":"裏世界の迷路の中で信じるべきは、妖精様の導きのみ！","ENG":"Only the Fairy Godmother could help us survive the maze that is the Counterside!","TWN":"在異界的迷宮裡，唯一能夠相信的就是妖精大人的引導！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"저, 정말? 그냥 감으로 찍은 좌표가 맞았다고?","JPN":"ほ、本当に？　適当に勘で選んだ座標が正しかったの？","ENG":"A-are you serious? The random coordinates worked?","TWN":"真…真的假的？妳隨手指的座標是對的？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"감이라니, 부정 타게! 이 수정구에 나타난 요정님의 계시에 따라……!","JPN":"勘だなんて、縁起でもないことを！　この水晶玉に現れた妖精様の啓示どおり……！","ENG":"They're not random! Are you trying to give us bad luck? I followed the Fairy Godmother's instructions, as shown on this crystal ball—","TWN":"什麼隨手，說話放尊重一點！我是按著水晶球裡妖精大人的指示……！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"클로에 양!","JPN":"クロエ！","ENG":"Chloe!","TWN":"克洛伊小姐！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L23_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"내가 보내 준 좌표 분석 자료는 잘 들어맞았나?","JPN":"私が送った座標分析資料はちゃんと合っていたのかね？","ENG":"Was my coordinates analysis accurate?","TWN":"我剛才給妳的座標分析資料有派上用場吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"다음에도 문제가 생기면 바로 연락하게나.","JPN":"もし問題が発生した時はすぐに連絡してくれ。","ENG":"Don't hesitate to let me know if you have more problems.","TWN":"下次有問題記得立刻找我喔！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"휴우, 다행이다. 다른 사람들도 우릴 따라서 제대로 온 것 같아.","JPN":"ふう、よかった。他の人たちもちゃんと私たちに付いて来れたみたい。","ENG":"Whew, thank goodness. I think the others were able to follow us, too.","TWN":"呼～真是太好了，其他人也跟著我們順利抵達。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"좋아! 녀석들한테 한 방 먹여 주자고!","JPN":"よし！　奴らに一発喰らわせてやろう！","ENG":"Great! Now, let's give 'em hell.","TWN":"很好！現在就給他們點顏色瞧瞧吧！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"네놈들, 내 경고를 무시하고 여기까지 쫓아오다니……","JPN":"貴様ら、俺の警告を無視してここまでおいかけてきやがって……","ENG":"You ignored my warning and followed us all the way here.","TWN":"你們這些傢伙，竟然無視我的警告追到這裡來……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"아무래도 혼이 덜 났나 보군 그래.","JPN":"どうやらお仕置きが足りなかったようだな？","ENG":"You haven't learned, have you?","TWN":"我剛才可能太親切了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"……오랜만이네요, 아줌마.","JPN":"……久しぶりです、おばさん。","ENG":"Long time, no see, old lady.","TWN":"……好久不見啦，大嬸！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"대장한테 잡힌 이후로 감옥에서 나사나 깎고 있는 줄 알았는데요.","JPN":"隊長に捕まった後、刑務所で労役でもしていると思ってましたよ。","ENG":"I thought you were turning screws in prison since you were captured by the Cap.","TWN":"妳栽在隊長手中後，我還以為妳乖乖在監獄裡數饅頭呢！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"뭐? 감히 어떤 녀석이……!","JPN":"あ？　なんでそんな話を……！","ENG":"What? How dare you—","TWN":"妳說什麼？這麼大口氣……！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"잠깐, 넌 알트 소대의 그 저격수?!","JPN":"待て、お前はアルト小隊の狙撃手か！？","ENG":"Wait, you're the ALT Squad sniper!","TWN":"等等，妳是那個阿爾特小隊的狙擊手？！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"그러고 보니 그 함선도……. 첫 교전 때 우리한테 한 방 먹였던 고물이군.","JPN":"そういえばあの艦船も……初めての交戦の時俺らの邪魔をしていたボロ船だな。","ENG":"Now that I think of it, that ship... It's the piece of junk that caused us so much trouble during our first engagement.","TWN":"這麼說來……那艘艦船也是第一次交手時，讓我們陷入苦戰的古董吧！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"설마 네 녀석들도 우릴 쫓아온 건가?","JPN":"まさか、お前らも追いかけて来たのか？","ENG":"Did you come after us, too?","TWN":"你們該不會也追我們追到這裡來吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"그렇게 됐네요. 이런 데서 다시 만날지는 몰랐지만요.","JPN":"まあそういうことです。こんな所で再会するとは思いませんでしたよ。","ENG":"Yes, unfortunately. I never thought I'd see you again like this.","TWN":"總之就是這麼回事囉～沒想到會在這裡又遇到妳。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"그래. 차라리 잘됐군.","JPN":"ああ。ラッキーかもしれないな。","ENG":"Well, might as well.","TWN":"也好，新仇舊恨一次解決吧！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"이 심연 구렁텅이에서 너흴 또 만나다니, 정말 사랑스러운 악연이야.","JPN":"この深淵のどん底でお前らにまた会えるなんて、実に愛おしい悪縁だ。","ENG":"Destiny must love us so much. It brought us together in the middle of this bottomless pit yet again.","TWN":"竟然在這裡又遇到你們，真的是甜蜜的孽緣呢！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"저번에도 비참하게 패배한 주제에 자신만만하네요.","JPN":"この前は惨めに敗北したくせに、自信満々ですね。","ENG":"You still haven't lost your confidence since your miserable defeat the last time.","TWN":"現在講話那麼大聲，上次明明輸那麼慘～"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"어떻게 탈옥했는지는 모르겠지만, 또 망신당하기 싫으면 얌전히 항복이나 하시죠.","JPN":"どうやって脱獄したのかは分かりませんが、また恥をかきたくなければ大人しく降伏してください。","ENG":"I don't know how you escaped, but I suggest you surrender and save yourself the same humiliation as before.","TWN":"雖然我不清楚妳是怎麼逃獄的，但不想再輸一次的話，就乖乖束手就擒吧！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"흥. 그때는 조금 상성이 나빴을 뿐이야.","JPN":"ふん、あの時はちょっと相性が悪かっただけだ。","ENG":"Hmpf, I was just a bit unlucky the last time.","TWN":"哼！我那時候只是剛好狀態不太好！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"그리고 오늘은 아주 특별한 무기도 내 손에 있다고.","JPN":"それに今日は特別な武器があるんだ。","ENG":"Plus, I've got a very special weapon today.","TWN":"而且我今天可是有拿到秘密武器！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"특별한 무기?","JPN":"特別な武器？","ENG":"A special weapon?","TWN":"秘密武器？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"뭐야? 설마 아무것도 모르고 우릴 쫓아온 건가?","JPN":"なんだ？　もしかして何も知らずに追いかけて来たのか？","ENG":"Wait, don't you know what you're really after?","TWN":"妳不知道嗎？不知道還敢這樣追著我們跑啊？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"좋아. 특별히 가르쳐 주지, 알트 소대.","JPN":"よし、特別に教えてやる、アルト小隊。","ENG":"Okay, I'll tell you, Alt Squad.","TWN":"好吧！我就大發慈悲地告訴你們吧，阿爾特小隊！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"알파트릭스 그룹에서 그 난리를 치면서 우릴 붙잡으려 한 이유가 뭔지.","JPN":"アルファトリックスグループがあんなに目を光らせて俺らを捕まえようとした理由が何なのか。","ENG":"Why the Alphatrix Group is so desperate to catch us.","TWN":"阿爾法崔克斯集團為什麼會這麼大動作地要抓我們？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"우리가 인양해 온 연구선에 뭐가 있었는지.","JPN":"俺らが引き揚げた研究船に何があったのか。","ENG":"What's in the research ship you're after.","TWN":"我們搶來的那艘研究船裡面到底有什麼？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"지금부터…… 똑똑히 보여 주마.","JPN":"今から……はっきり見せてやる。","ENG":"I'll show you... now.","TWN":"我現在……就讓你們看個明白！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>이봐! 방금 탐지기에 엄청난 규모의 에너지 파형이 감지됐다!</color>","JPN":"<color=#ffd34c>おい！　今探知機に莫大な規模のエネルギー波形が感知されたぞ！</color>","ENG":"<color=#ffd34c>Hey! Our sensor has detected waves of tremendous energy!</color>","TWN":"                      "},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>이런 젠장! 출격했던 전투기들이 모두 격추당했어! 어떻게 된 거지?</color>","JPN":"<color=#ffd34c>まずい！　出撃した戦闘機がすべて撃墜された！　どうなっている！？</color>","ENG":"<color=#ffd34c>Drat! All our fighters have been shot down! What happened?</color>","TWN":"<color=#ffd34c>該死！我們派出去的戰鬥機都被擊落了！怎麼會這樣？</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>잠깐! 적 함선에서 뭔가 나온다! 저건……!</color>","JPN":"<color=#ffd34c>待て！　敵の艦船から何かが出てきた！　あれは……！</color>","ENG":"<color=#ffd34c>Hang on! Something's coming out of the enemy ship! That's...</color>","TWN":"<color=#ffd34c>等等！敵人的艦船裡好像跑出什麼東西？那個是……！</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"방금 저 함선…… 폭발했어?","JPN":"今あの艦船……爆発した？","ENG":"That ship... Did it really explode?","TWN":"剛才那艘艦船……爆炸了？"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>미확인 대형 개체가 본 함으로 접근 중!</color>","JPN":"<color=#ffd34c>未確認大型個体が本艦に接近中！</color>","ENG":"<color=#ffd34c>A large, unidentified object is approaching our ship!</color>","TWN":"<color=#ffd34c>有不知名的大型物體正朝本艦接近中！</color>"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>회피기동해! 어서!</color>","JPN":"<color=#ffd34c>回避を！　急げ！</color>","ENG":"<color=#ffd34c>Activate evasive maneuvers! Now!</color>","TWN":"<color=#ffd34c>立刻啟動迴避機制！快！</color>"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>붙잡혔다! 빠져나올 수가 없어……!</color>","JPN":"<color=#ffd34c>はめられた！　抜け出せない……！</color>","ENG":"<color=#ffd34c>We're caught! We can't get away!</color>","TWN":"<color=#ffd34c>被抓到了！無法掙脫……！</color>"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L31_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"아군 함선, 격침 확인!","JPN":"味方艦船、撃沈確認！","ENG":"Our allied ships are shot down!","TWN":"我方艦船，確定遭擊沉！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"전혀 대응하지 못하고 있습니다!","JPN":"まったく対応しきれていません！","ENG":"They went down without a fight!","TWN":"現在完全無法應付敵人的攻擊！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"설마……","JPN":"まさか……","ENG":"No...","TWN":"難道……"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"저게, 블랙 네트워크에서 말하던 그……","JPN":"あれが、ブラックネットワークで言われていた例の……","ENG":"That can't be what they talked about on the Dark Network...","TWN":"那個就是黑色網路說的……"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>의, 의뢰고 뭐고 우린 빠지겠어! 너희들도 알아서……!</color>","JPN":"<color=#ffd34c>い、依頼も何も私たちは抜ける！　あんたたちも逃げ……！</color>","ENG":"<color=#ffd34c>W-we're not getting paid enough for this! We're out! You should also—</color>","TWN":"<color=#ffd34c>管他委託還什麼的，我們不管了！你們也自己看著……！</color>"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>저, 저게 뭐야?! 으아아아악!</color>","JPN":"<color=#ffd34c>あ、あれは何だ！？　うわああああ！</color>","ENG":"<color=#ffd34c>W-what the heck is that? Waaah!</color>","TWN":"<color=#ffd34c>那…那是什麼？！呃啊啊啊！</color>"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"좋아. 날파리들은 처리했고…….","JPN":"よし。雑魚処理は終わったし……","ENG":"Alright, now the gnats are gone...","TWN":"爽啦！既然蒼蠅都處理掉了……"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"다음은 너희 차례다. 알트 소대.","JPN":"次はお前たちの番だ、アルト小隊。","ENG":"It's your turn, ALT Squad.","TWN":"那接下來就輪到你們囉，阿爾特小隊！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};